20	// Host returns the scheme and host. Host can be configured via the OLLAMA_HOST environment variable.
21	// Default is scheme "http" and host "127.0.0.1:11434"
22	func Host() *url.URL {
23		defaultPort := "11434"
24	
25		s := strings.TrimSpace(Var("OLLAMA_HOST"))
26		scheme, hostport, ok := strings.Cut(s, "://")
27		switch {
28		case !ok:
29			scheme, hostport = "http", s
30			if s == "ollama.com" {
31				scheme, hostport = "https", "ollama.com:443"
32			}
33		case scheme == "http":
34			defaultPort = "80"
35		case scheme == "https":
36			defaultPort = "443"
37		}
38	
39		hostport, path, _ := strings.Cut(hostport, "/")
40		host, port, err := net.SplitHostPort(hostport)
41		if err != nil {
42			host, port = "127.0.0.1", defaultPort
43			if ip := net.ParseIP(strings.Trim(hostport, "[]")); ip != nil {
44				host = ip.String()
45			} else if hostport != "" {
46				host = hostport
47			}
48		}
49	
50		if n, err := strconv.ParseInt(port, 10, 32); err != nil || n > 65535 || n < 0 {
51			slog.Warn("invalid port, using default", "port", port, "default", defaultPort)
52			port = defaultPort
53		}
54	
55		return &url.URL{
56			Scheme: scheme,
57			Host:   net.JoinHostPort(host, port),
58			Path:   path,
59		}
60	}
