62	// ConnectableHost returns Host() with unspecified bind addresses (0.0.0.0, ::)
63	// replaced by the corresponding loopback address (127.0.0.1, ::1).
64	// Unspecified addresses are valid for binding a server socket but not for
65	// connecting as a client, which fails on Windows.
66	func ConnectableHost() *url.URL {
67		u := Host()
68		host, port, err := net.SplitHostPort(u.Host)
69		if err != nil {
70			return u
71		}
72	
73		if ip := net.ParseIP(host); ip != nil && ip.IsUnspecified() {
74			if ip.To4() != nil {
75				host = "127.0.0.1"
76			} else {
77				host = "::1"
78			}
79			u.Host = net.JoinHostPort(host, port)
80		}
81	
82		return u
83	}
